      expect(pool2.reader().pragma('busy_timeout', { simple: true })).toBe(5000);
    } finally {
      pool2.close();
    }
  });

  it('a second pool writer has foreign_keys=ON', () => {
    const { dbPath, pool: pool1 } = makeTmpDb();
    pool1.close();
    const pool2 = openDbPool(dbPath);
