               (id, name, spec, pipeline, config, status, created_at, updated_at)
             VALUES ('wf-partial', 'test', '{}', '[]', '{}', 'pending',
                     '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z')`,
          ).run();
          throw new Error('abort-after-first-write');
        }),
